# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(account_balances, transactions):
    for transaction in transactions:
        account_id, amount = transaction['account_id'], transaction['amount']
        if account_id in account_balances:
            account_balances[account_id] += amount
        else:
            account_balances[account_id] = amount
    return account_balances

# Example usage
account_balances = {'123': 1000, '456': 500}
transactions = [{'account_id': '123', 'amount': -200}, {'account_id': '789', 'amount': 300}]
